\mgchapter{Działania na przedziałach}

\section{Teoria}

\begin{definition}[Przedział]
\textbf{Przedział} to zbiór wszystkich liczb rzeczywistych spełniających określony warunek dotyczący ich położenia na osi liczbowej. Wyróżniamy następujące rodzaje przedziałów dla liczb $a < b$:
\begin{itemize}
    \item $\langle a, b \rangle = \{ x \in \mathbb{R} : a \leq x \leq b \}$ — przedział \textbf{domknięty},
    \item $(a, b) = \{ x \in \mathbb{R} : a < x < b \}$ — przedział \textbf{otwarty},
    \item $\langle a, b) = \{ x \in \mathbb{R} : a \leq x < b \}$ — przedział \textbf{lewostronnie domknięty},
    \item $(a, b\rangle = \{ x \in \mathbb{R} : a < x \leq b \}$ — przedział \textbf{prawostronnie domknięty},
    \item $(a, +\infty) = \{ x \in \mathbb{R} : x > a \}$,
    \item $\langle a, +\infty) = \{ x \in \mathbb{R} : x \geq a \}$,
    \item $(-\infty, b) = \{ x \in \mathbb{R} : x < b \}$,
    \item $(-\infty, b\rangle = \{ x \in \mathbb{R} : x \leq b \}$,
    \item $(-\infty, +\infty) = \mathbb{R}$ — cały zbiór liczb rzeczywistych.
\end{itemize}
Nieskończoności $+\infty$ oraz $-\infty$ \textbf{nigdy nie należą} do przedziału, dlatego przy nich zawsze stawiamy nawias okrągły.
\end{definition}

\begin{definition}[Suma przedziałów]
\textbf{Suma} przedziałów $A$ i $B$ (oznaczana $A \cup B$) to zbiór wszystkich elementów należących do $A$ \textbf{lub} do $B$ (lub do obu jednocześnie). Na osi liczbowej jest to połączenie obu przedziałów.
\end{definition}

\begin{definition}[Część wspólna przedziałów]
\textbf{Część wspólna} przedziałów $A$ i $B$ (oznaczana $A \cap B$) to zbiór wszystkich elementów należących jednocześnie do $A$ \textbf{i} do $B$. Na osi liczbowej jest to fragment wspólny obu przedziałów.
\end{definition}

\begin{definition}[Różnica przedziałów]
\textbf{Różnica} przedziałów $A$ i $B$ (oznaczana $A \setminus B$) to zbiór wszystkich elementów należących do $A$, które \textbf{nie należą} do $B$. Na osi liczbowej jest to fragment przedziału $A$ po usunięciu z niego części wspólnej z $B$.
\end{definition}

\begin{tip}[Jak wykonywać działania na przedziałach?]
Najwygodniejszą metodą wykonywania działań na przedziałach jest \textbf{rysunek osi liczbowej}:
\begin{enumerate}
    \item Zaznacz oba przedziały na wspólnej osi liczbowej.
    \item \textbf{Suma} ($\cup$): zamaluj wszystko, co pokrywa choć jeden z przedziałów.
    \item \textbf{Część wspólna} ($\cap$): pozostaw tylko fragment pokryty przez \textbf{oba} przedziały jednocześnie.
    \item \textbf{Różnica} ($A \setminus B$): z przedziału $A$ usuń część wspólną z $B$.
    \item Pamiętaj o typie nawiasów na końcach wynikowego przedziału:
    \begin{itemize}
        \item jeśli punkt \textbf{należy} do wyniku — nawias kwadratowy $\langle$ lub $\rangle$,
        \item jeśli punkt \textbf{nie należy} do wyniku — nawias okrągły $($ lub $)$.
    \end{itemize}
\end{enumerate}
\end{tip}

\begin{tip}[Suma rozłącznych przedziałów]
Jeśli dwa przedziały \textbf{nie mają punktów wspólnych}, ich suma zapisywana jest za pomocą symbolu alternatywy zbiorowej. Na przykład: $(-\infty, 1) \cup (3, +\infty)$. Takiej sumy \textbf{nie można} zapisać jako jednego przedziału.
\end{tip}

\section{Przykłady}

% -----------------------------------------------------------------------
% 1. Wyznaczanie sumy przedziałów
% -----------------------------------------------------------------------

\begin{problem}[Poziom podstawowy]
Wyznaczy sumę przedziałów $A = \langle -2, 3 \rangle$ oraz $B = (1, 6)$.

\begin{solution}
\textbf{Krok 1. Narysuj oba przedziały na osi liczbowej.}

\begin{plot}[Przedziały $A = \langle -2, 3 \rangle$ oraz $B = (1, 6)$]
\begin{tikzpicture}
    % Axes
    \draw[->, thick, mgColorPlot2] (-3.5,0) -- (7.5,0) node[right] {$x$};
    % Ticks and labels
    \foreach \x/\l in {-2/{-2}, 1/{1}, 3/{3}, 6/{6}} {
        \draw[mgColorPlot2] (\x, 0.08) -- (\x, -0.08) node[below] {\small$\l$};
    }

    % Interval A = [-2, 3] — top row, y=0.5
    \draw[mgColorPlot1, line width=2pt] (-2, 0.5) -- (3, 0.5);
    \filldraw[mgColorPlot1] (-2, 0.5) circle (3pt);
    \filldraw[mgColorPlot1] (3,  0.5) circle (3pt);
    \node[mgColorPlot1, left] at (-3.2, 0.5) {\small$A$};

    % Interval B = (1, 6) — middle row, y=0.5+0.55
    \draw[mgColorPlot2, line width=2pt] (1, 1.1) -- (6, 1.1);
    \draw[mgColorPlot2, line width=2pt, fill=white] (1, 1.1) circle (3pt);
    \draw[mgColorPlot2, line width=2pt, fill=white] (6, 1.1) circle (3pt);
    \node[mgColorPlot2, left] at (-3.2, 1.1) {\small$B$};

    % Result A ∪ B = [-2, 6) — bottom row, y=-0.7
    \draw[mgColorAccent, line width=2pt] (-2, -0.7) -- (6, -0.7);
    \filldraw[mgColorAccent]  (-2, -0.7) circle (3pt);
    \draw[mgColorAccent, line width=2pt, fill=white] (6, -0.7) circle (3pt);
    \node[mgColorAccent, left] at (-3.2, -0.7) {\small$A \cup B$};
\end{tikzpicture}
\end{plot}

\textbf{Krok 2. Oceń zachodzenie przedziałów.}

Przedziały $A = \langle -2, 3 \rangle$ oraz $B = (1, 6)$ \textbf{nachodzą na siebie}, ponieważ mają wspólny fragment $(1, 3\rangle$.

\textbf{Krok 3. Wyznacz sumę.}

Suma zawiera wszystkie punkty należące do $A$ lub $B$:
\[
    A \cup B = \langle -2, 6).
\]

\textbf{Uzasadnienie nawiasów:}
\begin{itemize}
    \item Lewa granica: $-2$ należy do $A$ (nawias kwadratowy $\langle$).
    \item Prawa granica: $6$ \textbf{nie} należy do $B$ (nawias okrągły $)$).
\end{itemize}

\[
    \boxed{A \cup B = \langle -2, 6)}
\]
\end{solution}
\end{problem}

% -----------------------------------------------------------------------
% 2. Wyznaczanie różnicy przedziałów
% -----------------------------------------------------------------------

\begin{problem}[Poziom podstawowy]
Wyznaczy różnicę przedziałów $A = \langle -1, 5 \rangle$ oraz $B = \langle 2, 7 \rangle$.

\begin{solution}
\textbf{Krok 1. Narysuj oba przedziały na osi liczbowej.}

\begin{plot}[Przedziały $A = \langle -1, 5 \rangle$ oraz $B = \langle 2, 7 \rangle$]
\begin{tikzpicture}
    % Axes
    \draw[->, thick, mgColorPlot2] (-2.5,0) -- (8.5,0) node[right] {$x$};
    \foreach \x/\l in {-1/{-1}, 2/{2}, 5/{5}, 7/{7}} {
        \draw[mgColorPlot2] (\x, 0.08) -- (\x, -0.08) node[below] {\small$\l$};
    }

    % A = [-1, 5]
    \draw[mgColorPlot1, line width=2pt] (-1, 0.5) -- (5, 0.5);
    \filldraw[mgColorPlot1] (-1, 0.5) circle (3pt);
    \filldraw[mgColorPlot1] (5,  0.5) circle (3pt);
    \node[mgColorPlot1, left] at (-2.2, 0.5) {\small$A$};

    % B = [2, 7]
    \draw[mgColorPlot2, line width=2pt] (2, 1.1) -- (7, 1.1);
    \filldraw[mgColorPlot2] (2, 1.1) circle (3pt);
    \filldraw[mgColorPlot2] (7, 1.1) circle (3pt);
    \node[mgColorPlot2, left] at (-2.2, 1.1) {\small$B$};

    % Result A \ B = [-1, 2)
    \draw[mgColorAccent, line width=2pt] (-1, -0.7) -- (2, -0.7);
    \filldraw[mgColorAccent]  (-1, -0.7) circle (3pt);
    \draw[mgColorAccent, line width=2pt, fill=white] (2, -0.7) circle (3pt);
    \node[mgColorAccent, left] at (-2.2, -0.7) {\small$A \setminus B$};
\end{tikzpicture}
\end{plot}

\textbf{Krok 2. Znajdź część wspólną.}

\[
    A \cap B = \langle 2, 5 \rangle.
\]

\textbf{Krok 3. Wyznacz różnicę.}

Różnica $A \setminus B$ to elementy należące do $A$, które \textbf{nie należą} do $B$, tzn. usuwamy z $A$ fragment $\langle 2, 5 \rangle$:
\[
    A \setminus B = \langle -1, 2).
\]

\textbf{Uzasadnienie nawiasów:}
\begin{itemize}
    \item Lewa granica: $-1$ należy do $A$ i nie leży w $B$ — zostaje (nawias $\langle$).
    \item Prawa granica: $2$ należy do $B$, więc \textbf{musi być usunięte} z wyniku (nawias okrągły $)$).
\end{itemize}

\[
    \boxed{A \setminus B = \langle -1, 2)}
\]
\end{solution}
\end{problem}

% -----------------------------------------------------------------------
% 3. Wyznaczanie części wspólnej przedziałów
% -----------------------------------------------------------------------

\begin{problem}[Poziom podstawowy]
Wyznaczy część wspólną przedziałów $A = (-\infty, 4\rangle$ oraz $B = (-1, +\infty)$.

\begin{solution}
\textbf{Krok 1. Narysuj oba przedziały na osi liczbowej.}

\begin{plot}[Przedziały $A = (-\infty, 4\rangle$ oraz $B = (-1, +\infty)$]
\begin{tikzpicture}
    % Axes
    \draw[->, thick, mgColorPlot2] (-5,0) -- (6,0) node[right] {$x$};
    \foreach \x/\l in {-1/{-1}, 4/{4}} {
        \draw[mgColorPlot2] (\x, 0.08) -- (\x, -0.08) node[below] {\small$\l$};
    }

    % A = (-inf, 4]
    \draw[mgColorPlot1, line width=2pt] (-4.8, 0.5) -- (4, 0.5);
    \draw[->, mgColorPlot1, line width=2pt] (-4.8, 0.5) -- (-5, 0.5);
    \filldraw[mgColorPlot1] (4, 0.5) circle (3pt);
    \node[mgColorPlot1, right] at (4.2, 0.5) {};
    \node[mgColorPlot1, left] at (-5, 0.5) {\small$A$};

    % B = (-1, +inf)
    \draw[mgColorPlot2, line width=2pt] (-1, 1.1) -- (5.8, 1.1);
    \draw[->, mgColorPlot2, line width=2pt] (5.4, 1.1) -- (5.9, 1.1);
    \draw[mgColorPlot2, line width=2pt, fill=white] (-1, 1.1) circle (3pt);
    \node[mgColorPlot2, left] at (-5, 1.1) {\small$B$};

    % Result A ∩ B = (-1, 4]
    \draw[mgColorAccent, line width=2pt] (-1, -0.7) -- (4, -0.7);
    \draw[mgColorAccent, line width=2pt, fill=white] (-1, -0.7) circle (3pt);
    \filldraw[mgColorAccent] (4, -0.7) circle (3pt);
    \node[mgColorAccent, left] at (-5, -0.7) {\small$A \cap B$};
\end{tikzpicture}
\end{plot}

\textbf{Krok 2. Określ, który fragment osi należy do obu przedziałów jednocześnie.}

\begin{itemize}
    \item $A = (-\infty, 4\rangle$ — wszystkie liczby \textbf{nie większe} niż $4$,
    \item $B = (-1, +\infty)$ — wszystkie liczby \textbf{większe} niż $-1$.
\end{itemize}

Aby należeć do \textbf{obu} przedziałów, liczba musi być jednocześnie:
\[
    x \leq 4 \quad \text{i} \quad x > -1,
\]
co oznacza $-1 < x \leq 4$.

\textbf{Krok 3. Zapisz wynik.}

\[
    A \cap B = (-1, 4\rangle.
\]

\textbf{Uzasadnienie nawiasów:}
\begin{itemize}
    \item Lewa granica: $-1$ \textbf{nie} należy do $B$ — nie należy do wyniku (nawias $($).
    \item Prawa granica: $4$ należy do $A$ — należy do wyniku (nawias $\rangle$).
\end{itemize}

\[
    \boxed{A \cap B = (-1, 4\rangle}
\]
\end{solution}
\end{problem}

